import type { MessageFromTapeWorklet, MessageToTapeWorklet } from './types';
import {
  TAPE_LENGTH_IN_FRAMES,
  TAPE_STATE_SELECTED_TRACK_IDX,
  TAPE_STATE_NUM_CLIPS,
  TAPE_STATE_NEXT_CLIP_SAMPLE_IDX,
  TAPE_STATE_PLAYHEAD,
  TAPE_STATE_REC_BUTTON_DOWN,
  TAPE_STATE_PLAY_BUTTON_DOWN,
  TAPE_STATE_STOP_BUTTON_DOWN,
  TAPE_STATE_LEFT_BUTTON_DOWN,
  TAPE_STATE_RIGHT_BUTTON_DOWN,
  TAPE_STATE_RECORDING,
  TAPE_CLIP_TRACK_ID,
  TAPE_CLIP_START_FRAME_IDX,
  TAPE_CLIP_LENGTH,
  TAPE_CLIP_SAMPLES_START_IDX,
  TAPE_CLIP_STRUCT_SIZE,
  TAPE_STATE_LIFT_BUTTON_DOWN,
  TAPE_STATE_DROP_BUTTON_DOWN,
  TAPE_STATE_PLAYING_DIRECTION,
  TAPE_STATE_SHIFT_BUTTON_DOWN,
  TAPE_STATE_TIME_DIV,
  SAMPLE_RATE,
  TAPE_STATE_TEMPO,
  TAPE_STATE_SPLIT_BUTTON_DOWN,
  TAPE_STATE_LOOP_OUT_POINT,
  TAPE_STATE_LOOP_ON,
  TAPE_STATE_LOOP_IN_POINT,
  TAPE_STATE_LOOP_IN_BUTTON_DOWN,
  TAPE_STATE_LOOP_OUT_BUTTON_DOWN,
  TAPE_STATE_CLICK_ON,
  SAMPLE_RATE_RECIP,
  TAU,
} from './constants';
import { clamp } from './helpers';

interface ClipInfo {
  offset: number;
  track: number;
  samplesStartIdx: number;
  length: number;
  startFrameIdx: number;
}

const ARROW_SPEED_MAGNITUDE = 4;

const CLICK_SAMPLES = Math.round(0.032 * SAMPLE_RATE); // short click
const CLICK_FREQ_WEAK = 440;
const CLICK_FREQ_DOWNBEAT = 880;
const CLICK_LEVEL = 0.14;

class Tape extends AudioWorkletProcessor implements AudioWorkletProcessorImpl {
  state: Float32Array<any>;
  prevState: Float32Array<any>;
  clips: Float32Array<any>;
  clipSamples: Float32Array<any>[];
  nextFreeSampleIdx = [0, 0, 0, 0];
  recordingClipInfo: (ClipInfo & { numWraps: number }) | null = null;
  liftedClipInfo: ClipInfo | null = null;
  speed = 0;
  speedIncrement = 0;
  desiredSpeed = 0;
  latencyOffsetInChunks = 20;

  constructor() {
    super();
    this.port.onmessage = (msg: MessageEvent<MessageToTapeWorklet>) => this.onMessage(msg.data);
  }

  getGain(track: number) {
    return this.state[track];
  }

  setGain(track: number, value: number) {
    this.state[track] = value;
  }

  get timeDiv() {
    return this.state[TAPE_STATE_TIME_DIV];
  }

  set timeDiv(value: number) {
    this.state[TAPE_STATE_TIME_DIV] = value;
  }

  set selectedTrackIdx(value: number) {
    this.state[TAPE_STATE_SELECTED_TRACK_IDX] = value;
  }

  get selectedTrackIdx() {
    return this.state[TAPE_STATE_SELECTED_TRACK_IDX];
  }

  get numClips() {
    return this.state[TAPE_STATE_NUM_CLIPS];
  }

  set numClips(value: number) {
    this.state[TAPE_STATE_NUM_CLIPS] = value;
  }

  get nextNextClipSampleIdx() {
    return this.state[TAPE_STATE_NEXT_CLIP_SAMPLE_IDX];
  }

  set nextNextClipSampleIdx(value: number) {
    this.state[TAPE_STATE_NEXT_CLIP_SAMPLE_IDX] = value;
  }

  get playhead() {
    return this.state[TAPE_STATE_PLAYHEAD];
  }

  set playhead(value: number) {
    this.state[TAPE_STATE_PLAYHEAD] = value;
  }

  get recording() {
    return this.state[TAPE_STATE_RECORDING] === 1;
  }

  set recording(value: boolean) {
    this.state[TAPE_STATE_RECORDING] = value ? 1 : 0;
  }

  get playingDirection() {
    return this.state[TAPE_STATE_PLAYING_DIRECTION];
  }

  set playingDirection(value: number) {
    this.state[TAPE_STATE_PLAYING_DIRECTION] = value;
  }

  sendMessage(msg: MessageFromTapeWorklet, transferObjects: Transferable[] = []) {
    this.port.postMessage(msg, transferObjects);
  }

  onMessage(msg: MessageToTapeWorklet) {
    switch (msg.command) {
      case 'init': {
        this.state = new Float32Array<any>(msg.state);
        this.prevState = new Float32Array(this.state.length);
        this.clips = new Float32Array<any>(msg.clips);
        this.clipSamples = msg.clipSamples.map(buffer => new Float32Array<any>(buffer));
        this.setGain(0, 1);
        this.setGain(1, 1);
        this.setGain(2, 1);
        this.setGain(3, 1);
        this.timeDiv = 1 / 4;
        break;
      }
    }
  }

  process(inputs: Float32Array[][], [output]: Float32Array[][], _parameters: any) {
    if (!this.state) {
      // wait until we've been initialized
      return true;
    }

    this.handleButtonEvents();

    if (this.recording && !this.recordingClipInfo && Math.abs(this.desiredSpeed) === 1) {
      this.startRecording();
    }

    const numFrames = output[0].length;
    for (let frameIdx = 0; frameIdx < numFrames; frameIdx++) {
      if (this.speed !== 0) {
        this.mixClipsInto(output, frameIdx);
        if (this.recordingClipInfo) {
          this.recordFrame(inputs, frameIdx);
        }
      }

      const ph0 = this.playhead;
      this.advancePlayhead();
      const ph1 = this.playhead;

      if (this.state[TAPE_STATE_CLICK_ON] === 1) {
        this.triggerClickOnQuarterCrossings(ph0, ph1);
      }

      this.mixClickInto(output, frameIdx);
    }
    return true;
  }

  startRecording() {
    this.recording = true;
    this.speed = this.desiredSpeed = this.playingDirection;

    const offset = this.numClips++ * TAPE_CLIP_STRUCT_SIZE;
    const track = this.selectedTrackIdx;
    const startFrameIdx =
      this.playingDirection > 0 ? Math.floor(this.playhead) : Math.ceil(this.playhead);
    const samplesStartIdx = this.nextFreeSampleIdx[track];
    const length = 0;
    this.recordingClipInfo = { offset, track, startFrameIdx, samplesStartIdx, length, numWraps: 0 };
    this.clips[offset + TAPE_CLIP_TRACK_ID] = track;
    this.clips[offset + TAPE_CLIP_START_FRAME_IDX] = startFrameIdx;
    this.clips[offset + TAPE_CLIP_SAMPLES_START_IDX] = samplesStartIdx;
    this.clips[offset + TAPE_CLIP_LENGTH] = length;
  }

  recordFrame(inputs: Float32Array[][], frameIdx: number) {
    const { offset, track, samplesStartIdx, startFrameIdx } = this.recordingClipInfo;
    let sample = 0;
    for (const input of inputs) {
      sample += input[0]?.[frameIdx] ?? 0;
    }

    const ph = Math.floor(this.playhead);
    if (startFrameIdx <= ph && ph < startFrameIdx + this.recordingClipInfo.length) {
      const sampleIdx = samplesStartIdx + ph - startFrameIdx;
      this.clipSamples[track][sampleIdx] += sample; // note: this is an overdub! (good for recording while looping)
      return;
    }

    this.recordingClipInfo.length++;
    const sampleIdx = samplesStartIdx + this.clips[offset + TAPE_CLIP_LENGTH]++;
    this.clipSamples[track][sampleIdx] = sample;
    this.nextFreeSampleIdx[track]++;

    if (this.playingDirection < 1) {
      // recording backwards, so move the start of the clip back by one sample
      this.recordingClipInfo.startFrameIdx -= 1;
      this.clips[offset + TAPE_CLIP_START_FRAME_IDX] -= 1;
    }
  }

  stopRecording(recButtonGoesUp = true) {
    if (this.playingDirection < 1 && this.recordingClipInfo?.numWraps === 0) {
      this.reverseRecordingClipSamples();
    }

    this.recording = false;
    this.recordingClipInfo = null;
    if (recButtonGoesUp) {
      this.state[TAPE_STATE_REC_BUTTON_DOWN] = 0;
    }
  }

  reverseRecordingClipSamples() {
    const { track, samplesStartIdx, length } = this.recordingClipInfo;
    const buf = this.clipSamples[track];
    let lo = samplesStartIdx;
    let hi = samplesStartIdx + length - 1;
    while (lo < hi) {
      const t = buf[lo];
      buf[lo++] = buf[hi];
      buf[hi--] = t;
    }
  }

  recButtonLatches = false;

  handleButtonEvents() {
    this.handleButton(
      TAPE_STATE_REC_BUTTON_DOWN,
      () => (this.recording = true),
      () => {
        if (!this.recButtonLatches) {
          this.stopRecording();
        }
      }
    );
    this.handleButton(
      TAPE_STATE_PLAY_BUTTON_DOWN,
      () => {
        this.recButtonLatches = true;
        const oldDirection = this.playingDirection;
        this.playingDirection = this.state[TAPE_STATE_SHIFT_BUTTON_DOWN] === 1 ? -1 : 1;
        this.desiredSpeed = this.playingDirection;
        if (this.recordingClipInfo && oldDirection !== this.playingDirection) {
          this.stopRecording();
        } else if (Math.abs(this.desiredSpeed) === 1) {
          // go right away, don't accelerate to it
          this.speed = this.desiredSpeed;
          this.speedIncrement = 0;
        }
      },
      () => {
        this.recButtonLatches = false;
      }
    );
    this.handleButton(TAPE_STATE_STOP_BUTTON_DOWN, () => {
      if (this.isStopped()) {
        this.movePlayhead(this.loopInPoint);
      } else if (this.recording) {
        this.speed = 0;
        this.speedIncrement = 0;
        this.stopRecording();
      }
      this.desiredSpeed = 0;
      this.playingDirection = 0;
    });
    this.handleButton(
      TAPE_STATE_LEFT_BUTTON_DOWN,
      () => {
        if (this.state[TAPE_STATE_STOP_BUTTON_DOWN] === 1) {
          this.moveToStart();
        } else if (this.state[TAPE_STATE_SHIFT_BUTTON_DOWN] === 1) {
          this.moveToPrevDiv();
        } else if (!this.recording) {
          this.desiredSpeed = -ARROW_SPEED_MAGNITUDE;
        }
      },
      () => {
        if (!this.recording) {
          this.desiredSpeed = this.state[TAPE_STATE_RIGHT_BUTTON_DOWN]
            ? ARROW_SPEED_MAGNITUDE
            : this.playingDirection;
        }
      }
    );
    this.handleButton(
      TAPE_STATE_RIGHT_BUTTON_DOWN,
      () => {
        if (this.state[TAPE_STATE_STOP_BUTTON_DOWN] === 1) {
          this.moveToEnd();
        } else if (this.state[TAPE_STATE_SHIFT_BUTTON_DOWN] === 1) {
          this.moveToNextDiv();
        } else if (!this.recording) {
          this.desiredSpeed = ARROW_SPEED_MAGNITUDE;
        }
      },
      () => {
        if (!this.recording) {
          this.desiredSpeed = this.state[TAPE_STATE_LEFT_BUTTON_DOWN]
            ? -ARROW_SPEED_MAGNITUDE
            : this.playingDirection;
        }
      }
    );
    this.handleButton(TAPE_STATE_LIFT_BUTTON_DOWN, () => {
      if (!this.recording) {
        this.lift();
      }
    });
    this.handleButton(TAPE_STATE_DROP_BUTTON_DOWN, () => {
      if (!this.recording) {
        this.drop();
      }
    });
    this.handleButton(TAPE_STATE_SPLIT_BUTTON_DOWN, () => {
      if (!this.recording) {
        this.split();
      }
    });
    this.handleButton(TAPE_STATE_LOOP_IN_BUTTON_DOWN, () => {
      this.setLoopInPoint();
    });
    this.handleButton(TAPE_STATE_LOOP_OUT_BUTTON_DOWN, () => {
      this.setLoopOutPoint();
    });

    if (!this.recording) {
      const u = 0.0001;
      const dir = this.desiredSpeed > this.speed ? 1 : -1;
      if (this.speed === 0 && this.desiredSpeed === 1) {
        this.speedIncrement = 1.5 * u * dir;
      } else if (this.desiredSpeed === 0) {
        // always take the same amount of time to come to a stop
        this.speedIncrement = Math.abs(this.speed) * u * dir;
      } else if (this.speed * this.desiredSpeed < 0) {
        // always take the same amount of time to change direction
        this.speedIncrement = (this.desiredSpeed - this.speed) * 0.5 * u;
      } else {
        this.speedIncrement = 0.75 * u * dir;
      }
    }

    this.prevState.set(this.state);
  }

  handleButton(stateIdx: number, onDown: () => void, onUp?: () => void) {
    if (this.state[stateIdx] === 1 && this.prevState[stateIdx] === 0) {
      onDown();
    } else if (this.state[stateIdx] === 0 && this.prevState[stateIdx] === 1) {
      onUp?.();
    }
  }

  mixClipsInto(output: Float32Array[], outputFrameIdx: number) {
    let sample = 0;
    this.forEachClip((trackIdx, startFrameIdx, length, samplesStartIdx, offset) => {
      // if (this.recordingClipInfo && offset === this.recordingClipInfo.offset) {
      //   return;
      // }
      sample +=
        this.getSampleAtPlayhead(trackIdx, startFrameIdx, length, samplesStartIdx) *
        this.getGain(trackIdx);
    });
    for (let channel = 0; channel < output.length; channel++) {
      output[channel][outputFrameIdx] += sample;
    }
  }

  forEachClip(
    fn: (
      trackIdx: number,
      startFrameIdx: number,
      length: number,
      samplesStartIdx: number,
      offset: number
    ) => void
  ) {
    for (let i = 0; i < this.numClips; i++) {
      const offset = i * TAPE_CLIP_STRUCT_SIZE;
      const trackIdx = this.clips[offset + TAPE_CLIP_TRACK_ID];
      const startFrameIdx = this.clips[offset + TAPE_CLIP_START_FRAME_IDX];
      const length = this.clips[offset + TAPE_CLIP_LENGTH];
      const samplesStartIdx = this.clips[offset + TAPE_CLIP_SAMPLES_START_IDX];
      fn(trackIdx, startFrameIdx, length, samplesStartIdx, offset);
    }
  }

  getSampleAtPlayhead(
    trackIdx: number,
    clipStartFrameIdx: number,
    clipLength: number,
    clipSamplesStartIdx: number
  ) {
    const frameIdx = this.playhead - clipStartFrameIdx;
    if (frameIdx < -1 || frameIdx >= clipLength) {
      return 0;
    }

    const clipSamples = this.clipSamples[trackIdx];
    const clipSampleIdx = Math.floor(clipSamplesStartIdx + frameIdx);

    // without interpolation
    // return clipSamples[clipSampleIdx];

    // with interpolation
    const v1 = frameIdx < 0 ? 0 : clipSamples[clipSampleIdx];
    const v2 = frameIdx >= clipLength ? 0 : clipSamples[clipSampleIdx + 1];
    const f = this.playhead - Math.floor(this.playhead);
    return (1 - f) * v1 + f * v2;
  }

  inLoop() {
    return (
      this.state[TAPE_STATE_LOOP_ON] === 1 &&
      Number.isFinite(this.state[TAPE_STATE_LOOP_IN_POINT]) &&
      Number.isFinite(this.state[TAPE_STATE_LOOP_OUT_POINT]) &&
      this.loopInPoint <= this.playhead &&
      this.playhead <= this.loopOutPoint
    );
  }

  get loopInPoint() {
    return clamp(this.state[TAPE_STATE_LOOP_IN_POINT], 0, TAPE_LENGTH_IN_FRAMES);
  }

  get loopOutPoint() {
    return clamp(this.state[TAPE_STATE_LOOP_OUT_POINT], this.loopInPoint, TAPE_LENGTH_IN_FRAMES);
  }

  private playheadWrapped = false;

  advancePlayhead() {
    this.playheadWrapped = false;
    const couldWrap = this.inLoop() && Math.abs(this.desiredSpeed) === 1;
    this.movePlayhead(this.playhead + this.speed);

    if (couldWrap) {
      if (this.speed > 0 && this.playhead >= this.loopOutPoint) {
        this.playheadWrapped = true;
        this.playhead = this.loopInPoint + this.playhead - this.loopOutPoint;
      } else if (this.speed < 0 && this.playhead < this.loopInPoint) {
        this.playheadWrapped = true;
        this.playhead = this.loopOutPoint - (this.loopInPoint - this.playhead);
      }
      if (this.playheadWrapped && this.recordingClipInfo) {
        this.handleWrapWhileRecording();
      }
    }

    if (this.speed === this.desiredSpeed) {
      // no adjustment needed
    } else if (
      Math.abs(this.desiredSpeed - this.speed) < Math.abs(this.speedIncrement) ||
      (this.desiredSpeed === 0 && Math.abs(this.speed) < 1e-2)
    ) {
      this.speed = this.desiredSpeed;
    } else {
      this.speed += this.speedIncrement;
    }
  }

  movePlayhead(newValue: number) {
    if (newValue < 0) {
      newValue = 0;
      this.speed = 0;
    } else if (newValue > TAPE_LENGTH_IN_FRAMES) {
      this.speed = 0;
      this.desiredSpeed = 0;
      this.state[TAPE_STATE_PLAY_BUTTON_DOWN] = 0;
      this.stopRecording();
      newValue = TAPE_LENGTH_IN_FRAMES;
    }
    this.playhead = newValue;
  }

  handleWrapWhileRecording() {
    if (++this.recordingClipInfo.numWraps !== 1) {
      // we only care about the first wrap
      return;
    }

    if (this.playingDirection < 0) {
      this.reverseRecordingClipSamples();
    }

    const { offset, track, startFrameIdx, samplesStartIdx, length } = this.recordingClipInfo;

    if (startFrameIdx < this.loopInPoint || startFrameIdx >= this.loopOutPoint) {
      // the clip already includes the entire loop, so we're OK
      return;
    }

    if (this.playingDirection > 0) {
      // going forwards:   |>    |====<|

      // 1. allocate more samples
      const n = startFrameIdx - this.loopInPoint;
      this.nextFreeSampleIdx[track] += n;
      this.recordingClipInfo.length += n;
      this.clips[offset + TAPE_CLIP_LENGTH] += n;
      // note: the local variable `length` still has the old value, and we'll use it below

      // 2. shift clip left to the start of the loop
      this.recordingClipInfo.startFrameIdx = this.loopInPoint;
      this.clips[offset + TAPE_CLIP_START_FRAME_IDX] = this.loopInPoint;

      // 3. move the samples we already recorded to the right
      // (that way they don't move relative to the tape)
      this.clipSamples[track].copyWithin(samplesStartIdx + n, samplesStartIdx, length);

      // 4. zero out the new samples
      this.clipSamples[track].fill(0, samplesStartIdx, samplesStartIdx + n);
    } else {
      // going backwards:   |>====|    <|

      // 0. reverse the samples we already recorded
      // (already did it above)

      // 1. allocate more samples
      const n = this.loopOutPoint - this.loopInPoint - length;
      this.nextFreeSampleIdx[track] += n;
      this.recordingClipInfo.length += n;
      this.clips[offset + TAPE_CLIP_LENGTH] += n;
      // note: the local variable `length` still has the old value, and we'll use it below

      // 2. zero out the new samples
      this.clipSamples[track].fill(0, samplesStartIdx + length, samplesStartIdx + length + n);
    }
  }

  split() {
    const clipInfo = this.thisClip();
    if (!clipInfo) {
      this.sendMessage({ event: 'log', message: 'no clip to split' });
      return;
    }

    // split the clip at the playhead
    const { offset, track, startFrameIdx, length, samplesStartIdx } = clipInfo;
    const ph = Math.floor(this.playhead);
    const numFramesLeftOver = startFrameIdx + length - ph;
    this.clips[offset + TAPE_CLIP_LENGTH] -= numFramesLeftOver;

    // add the new clip
    const newOffset = this.numClips++ * TAPE_CLIP_STRUCT_SIZE;
    this.clips[newOffset + TAPE_CLIP_TRACK_ID] = track;
    this.clips[newOffset + TAPE_CLIP_START_FRAME_IDX] = ph;
    this.clips[newOffset + TAPE_CLIP_LENGTH] = numFramesLeftOver;
    this.clips[newOffset + TAPE_CLIP_SAMPLES_START_IDX] =
      samplesStartIdx + length - numFramesLeftOver;
  }

  lift() {
    // find the last clip on this track that overlaps with the playhead
    // the second call allows the clip that ends at the playhead to be lifted
    const clipInfo = this.thisClip() ?? this.thisClip(true);
    if (!clipInfo) {
      this.sendMessage({ event: 'log', message: 'no clip to lift' });
      return;
    }

    if (this.liftedClipInfo) {
      // discard the old lifted clip's samples, since they'll no longer be reachable
      const { track, samplesStartIdx, length } = this.liftedClipInfo;
      this.clipSamples[track].copyWithin(
        samplesStartIdx,
        samplesStartIdx + length,
        this.nextFreeSampleIdx[track]
      );
      this.nextFreeSampleIdx[track] -= length;
    }

    // remove the clip from this.clips
    const offset = clipInfo.offset;
    this.clips.copyWithin(
      offset,
      offset + TAPE_CLIP_STRUCT_SIZE,
      this.numClips * TAPE_CLIP_STRUCT_SIZE
    );
    this.numClips--;

    // make this clip the new lifted clip
    this.liftedClipInfo = clipInfo;

    if (this.isStopped()) {
      // move the playhead to the start of the lifted clip
      this.playhead = clipInfo.startFrameIdx;
    }

    this.sendMessage({ event: 'log', message: 'lifted clip' });
  }

  drop() {
    if (!this.liftedClipInfo) {
      this.sendMessage({ event: 'log', message: 'no clip to drop' });
      return;
    }

    const { track, samplesStartIdx, length } = this.liftedClipInfo;

    // copy the samples to the track we're dropping onto
    const samples = this.clipSamples[track].subarray(samplesStartIdx, samplesStartIdx + length);
    const newClipSampleStartIdx = this.nextFreeSampleIdx[this.selectedTrackIdx];
    this.clipSamples[this.selectedTrackIdx].set(samples, newClipSampleStartIdx);
    this.nextFreeSampleIdx[this.selectedTrackIdx] += length;

    // add the new clip
    const quantizedPlayhead = Math.round(this.playhead);
    const offset = this.numClips++ * TAPE_CLIP_STRUCT_SIZE;
    this.clips[offset + TAPE_CLIP_TRACK_ID] = this.selectedTrackIdx;
    this.clips[offset + TAPE_CLIP_START_FRAME_IDX] = quantizedPlayhead;
    this.clips[offset + TAPE_CLIP_LENGTH] = length;
    this.clips[offset + TAPE_CLIP_SAMPLES_START_IDX] = newClipSampleStartIdx;

    if (this.isStopped()) {
      // move the playhead to just after the new clip
      this.playhead = quantizedPlayhead + length;
    }
  }

  thisClip(allowEndAtPlayhead: boolean = false): ClipInfo | null {
    return this.findClip(
      ci =>
        ci.track === this.selectedTrackIdx &&
        ci.startFrameIdx <= this.playhead &&
        (ci.startFrameIdx + ci.length > this.playhead ||
          (allowEndAtPlayhead && ci.startFrameIdx + ci.length === this.playhead)),
      (ci1, ci2) => ci1.offset > ci2.offset
    );
  }

  moveToPrevDiv() {
    const fpd = this.getFramesPerDiv();
    let frameIdx = Math.floor(this.playhead) - 1;
    const origDivIdx = this.divIndex(frameIdx, fpd);
    while (this.divIndex(frameIdx, fpd) === origDivIdx) {
      frameIdx--;
    }
    this.movePlayhead(frameIdx + 1);
  }

  moveToNextDiv() {
    const fpd = this.getFramesPerDiv();
    let frameIdx = Math.ceil(this.playhead) + 1;
    const origDivIdx = this.divIndex(frameIdx, fpd);
    while (this.divIndex(frameIdx, fpd) === origDivIdx) {
      frameIdx++;
    }
    this.movePlayhead(frameIdx - 1);
  }

  moveToStart() {
    this.movePlayhead(0);
  }

  moveToEnd() {
    const clipInfo = this.findClip(
      ci => true,
      (ci1, ci2) => ci1.startFrameIdx + ci1.length >= ci2.startFrameIdx + ci2.length
    );
    if (clipInfo) {
      this.movePlayhead(clipInfo.startFrameIdx + clipInfo.length);
    }
  }

  private divIndex(frameIdx: number, fpd: number) {
    return Math.floor(frameIdx / fpd);
  }

  getFramesPerDiv(div = this.state[TAPE_STATE_TIME_DIV]) {
    const secondsPerQuarterNote = 60 / this.state[TAPE_STATE_TEMPO];
    const secondsPerMeasure = 4 * secondsPerQuarterNote;
    const secondsPerDiv = secondsPerMeasure * div;
    return secondsPerDiv * SAMPLE_RATE;
  }

  findClip(
    predicate: (clipInfo: ClipInfo) => boolean = () => true,
    isBetter: (ci1: ClipInfo, ci2: ClipInfo) => boolean = (ci1, ci2) => true
  ): ClipInfo | null {
    let bestSoFar: ClipInfo | null = null;
    this.forEachClip((trackIdx, startFrameIdx, length, samplesStartIdx, offset) => {
      const ci = { offset, track: trackIdx, samplesStartIdx, length, startFrameIdx };
      if (!predicate(ci)) {
        return;
      }
      if (!bestSoFar || isBetter(ci, bestSoFar)) {
        bestSoFar = ci;
      }
    });
    return bestSoFar;
  }

  isStopped() {
    return this.speed === 0 && this.desiredSpeed === 0;
  }

  setLoopInPoint() {
    if (this.recordingClipInfo) {
      this.stopRecording();
    }
    this.state[TAPE_STATE_LOOP_IN_POINT] = Math.floor(this.state[TAPE_STATE_PLAYHEAD]);
    this.state[TAPE_STATE_LOOP_OUT_POINT] = Math.max(
      this.state[TAPE_STATE_LOOP_OUT_POINT],
      this.state[TAPE_STATE_LOOP_IN_POINT]
    );
  }

  setLoopOutPoint() {
    if (this.recordingClipInfo) {
      this.stopRecording();
    }
    this.state[TAPE_STATE_LOOP_OUT_POINT] = Math.floor(this.state[TAPE_STATE_PLAYHEAD]);
    this.state[TAPE_STATE_LOOP_IN_POINT] = Math.min(
      this.state[TAPE_STATE_LOOP_IN_POINT],
      this.state[TAPE_STATE_LOOP_OUT_POINT]
    );

    if (this.desiredSpeed === 1) {
      this.movePlayhead(this.loopInPoint);
    }
  }

  // click stuff (warning: mostly written by cursor!)

  clickFramesRemaining = 0;
  clickPhase = 0;
  clickFreq = CLICK_FREQ_WEAK;

  mixClickInto(output: Float32Array[], outputFrameIdx: number) {
    if (this.clickFramesRemaining <= 0) {
      return;
    }
    const elapsed = CLICK_SAMPLES - this.clickFramesRemaining;
    const t = elapsed / CLICK_SAMPLES;
    const env = Math.exp(-5 * t);
    const s = CLICK_LEVEL * env * Math.sin(this.clickPhase);
    this.clickPhase += TAU * this.clickFreq * SAMPLE_RATE_RECIP;
    this.clickFramesRemaining--;
    for (let channel = 0; channel < output.length; channel++) {
      output[channel][outputFrameIdx] += s;
    }
  }

  triggerClickOnQuarterCrossings(ph0: number, ph1: number) {
    if (ph0 === ph1) {
      return;
    }

    const fpq = this.getFramesPerDiv(0.25);
    const q0 = Math.floor(ph0 / fpq);
    const q1 = Math.floor(ph1 / fpq);
    const delta = ph1 - ph0;
    const step = this.speed;
    const stepOk = Math.abs(delta - step) < 0.05 + 0.02 * Math.abs(step);

    if (this.playheadWrapped) {
      this.startClick(q1);
    } else if (q0 === q1 || !stepOk) {
      // no op
    } else {
      this.startClick(q1);
    }
  }

  private startClick(quarterIndex: number) {
    this.clickFramesRemaining = CLICK_SAMPLES;
    this.clickPhase = 0;
    this.clickFreq = quarterIndex % 4 === 0 ? CLICK_FREQ_DOWNBEAT : CLICK_FREQ_WEAK;
  }
}

registerProcessor('tape', Tape);
